
"use server";

import { auth, db } from "@/lib/firebase"; // Added db
import { 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  signOut,
  type User as FirebaseUser // Import FirebaseUser type
} from "firebase/auth";
import { doc, setDoc, serverTimestamp } from "firebase/firestore"; // Added Firestore imports
import { redirect } from 'next/navigation';

// Helper function to create or update user profile
async function updateUserProfile(user: FirebaseUser, isNewUser: boolean = false) {
  if (!user) return;

  const userProfileRef = doc(db, "users", user.uid);
  const profileData: any = {
    uid: user.uid,
    email: user.email,
    displayName: user.displayName || null,
    photoURL: user.photoURL || null,
    lastLoginAt: serverTimestamp(),
  };

  if (isNewUser) {
    profileData.createdAt = serverTimestamp();
  }

  try {
    await setDoc(userProfileRef, profileData, { merge: true });
  } catch (error) {
    console.error("Error updating user profile:", error);
    // Optionally, handle this error more gracefully, e.g., by logging or alerting
  }
}

export async function signUpWithEmailPassword(prevState: any, formData: FormData) {
  const email = formData.get("email") as string;
  const password = formData.get("password") as string;
  const confirmPassword = formData.get("confirmPassword") as string;

  if (!email || !password) {
    return { message: "Email and password are required.", success: false };
  }
  if (password !== confirmPassword) {
    return { message: "Passwords do not match.", success: false };
  }

  try {
    const userCredential = await createUserWithEmailAndPassword(auth, email, password);
    await updateUserProfile(userCredential.user, true); // Create profile for new user
    redirect('/'); 
  } catch (error: any) {
    return { message: error.message || "Failed to sign up.", success: false };
  }
}

export async function signInWithEmailPassword(prevState: any, formData: FormData) {
  const email = formData.get("email") as string;
  const password = formData.get("password") as string;

  if (!email || !password) {
    return { message: "Email and password are required.", success: false };
  }

  try {
    const userCredential = await signInWithEmailAndPassword(auth, email, password);
    await updateUserProfile(userCredential.user); // Update profile (e.g., lastLoginAt)
    redirect('/');
  } catch (error: any) {
    return { message: error.message || "Failed to sign in.", success: false };
  }
}

export async function logout() {
  try {
    await signOut(auth);
  } catch (error: any) {
    console.error("Logout failed:", error);
  }
  redirect('/login');
}
